mapper.select:
SELECT bp.post_id, bp.user_id, u.nickname, bp.title, bp.content, bp.is_public, bp.view_count, bp.comment_count, bp.created_at, bp.updated_at,
r.rec_id, r.style_type, r.tpo_type,
ws.weather_status, ws.temp, ws.place_name
FROM board_post bp JOIN users u ON u.user_id = bp.user_id JOIN recommendation r ON r.rec_id = bp.rec_id LEFT JOIN weather_snapshot ws ON ws.weather_id = r.weather_id
WHERE bp.deleted_at IS NULL AND bp.is_public = TRUE
AND ws.weather_status = #{weather}
AND r.style_type = #{style}
AND r.tpo_type = #{tpo}
ORDER BY bp.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM board_post bp
JOIN recommendation r ON r.rec_id = bp.rec_id
LEFT JOIN weather_snapshot ws ON ws.weather_id = r.weather_id

WHERE bp.deleted_at IS NULL
  AND bp.is_public = TRUE


    AND ws.weather_status = #{weather}



    AND r.style_type = #{style}



    AND r.tpo_type = #{tpo}

SELECT user_id
FROM recommendation
WHERE rec_id = #{recId}

SELECT is_saved
FROM recommendation
WHERE rec_id = #{recId}

SELECT COUNT(*)
FROM recommendation
WHERE rec_id = #{recId}
